// Shared skeleton/undead pixel helpers. Local to this pack, reused across variants.
function ud_skull(p, cx, ty, bone, boneD, eye = P.emberL) {
  // cranium
  p.ellipse(cx, ty + 2, 3, 3, boneD);
  p.ellipse(cx, ty + 2, 2.4, 2.4, bone);
  p.ellipse(cx - 1, ty + 1, 1, 1, lighten(bone, 0.18));
  // jaw
  p.rect(cx - 2, ty + 4, 4, 2, boneD);
  p.rect(cx - 2, ty + 4, 4, 1, bone);
  p.px(cx - 1, ty + 5, boneD); p.px(cx, ty + 5, boneD); p.px(cx + 1, ty + 5, boneD);
  // eye sockets (glowing)
  p.rect(cx - 2, ty + 2, 1, 2, P.ink);
  p.rect(cx + 1, ty + 2, 1, 2, P.ink);
  p.px(cx - 2, ty + 2, eye); p.px(cx + 1, ty + 2, eye);
  // nasal cavity
  p.px(cx, ty + 3, P.ink);
}

function ud_ribs(p, cx, ty, by, bone, boneD) {
  // spine
  p.vline(ty, by, cx, boneD);
  // rib pairs
  for (let y = ty; y < by; y += 2) {
    p.hline(cx - 3, cx - 1, y, bone);
    p.hline(cx + 1, cx + 3, y, bone);
    p.px(cx - 3, y, boneD); p.px(cx + 3, y, boneD);
  }
}

// ---------------------------------------------------------------------------
// g_skeleton — bony footsoldier with a rusted cleaver. 16x18, feet anchored.
// ---------------------------------------------------------------------------
defineAnim('g_skeleton', 16, 18, 4, (p, f) => {
  const bone = P.bone, boneD = darken(P.bone, 0.32);
  const bob = (f === 1 || f === 3) ? 1 : 0;
  const step = f === 1 ? 1 : f === 3 ? -1 : 0;
  const oy = -bob;
  // leg bones
  p.vline(13 + oy, 17 + oy, 6, boneD); p.vline(13 + oy, 17 + oy, 9, boneD);
  p.vline(13 + oy, 16 + oy, 6, bone); p.vline(13 + oy, 16 + oy, 9, bone);
  if (step > 0) p.px(6, 17 + oy, boneD);
  if (step < 0) p.px(9, 17 + oy, boneD);
  // pelvis
  p.rect(5, 12 + oy, 6, 2, boneD);
  // rib cage
  ud_ribs(p, 8, 7 + oy, 12 + oy, bone, boneD);
  // collar / shoulders
  p.hline(4, 11, 7 + oy, bone);
  // arms (bone)
  p.vline(7 + oy, 11 + oy, 3, boneD);
  p.vline(7 + oy, 11 + oy, 12, boneD);
  // skull
  ud_skull(p, 8, 1 + oy, bone, boneD, P.emberL);
  // rusty cleaver in right hand
  p.vline(9 + oy, 13 + oy, 12, P.woodD);
  p.rect(11, 8 + oy, 3, 4, P.steelD);
  p.rect(11, 8 + oy, 3, 1, P.steel);
  p.px(13, 9 + oy, P.iron);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 6 });

// ---------------------------------------------------------------------------
// g_bonearcher — skeletal archer that looses bone arrows. 16x18.
// ---------------------------------------------------------------------------
defineAnim('g_bonearcher', 16, 18, 4, (p, f) => {
  const bone = mix(P.bone, P.greenD, 0.18), boneD = darken(bone, 0.34);
  const draw = (f === 2); // mid-frame: bowstring drawn
  const oy = (f === 1 || f === 3) ? -1 : 0;
  // legs
  p.vline(13 + oy, 17 + oy, 6, boneD); p.vline(13 + oy, 17 + oy, 9, boneD);
  p.vline(13 + oy, 16 + oy, 6, bone); p.vline(13 + oy, 16 + oy, 9, bone);
  p.rect(5, 12 + oy, 6, 2, boneD);
  ud_ribs(p, 8, 7 + oy, 12 + oy, bone, boneD);
  // tattered hood remnant
  p.ellipse(8, 3 + oy, 3.2, 2.6, P.greenD);
  ud_skull(p, 8, 1 + oy, bone, boneD, P.toxic);
  // bow held forward (left)
  p.line(2, 4 + oy, 2, 13 + oy, P.woodL);
  p.line(2, 4 + oy, 3, 3 + oy, P.woodD);
  p.line(2, 13 + oy, 3, 14 + oy, P.woodD);
  // bowstring + nocked arrow
  if (draw) {
    p.line(2, 4 + oy, 6, 8 + oy, P.gray3);
    p.line(2, 13 + oy, 6, 8 + oy, P.gray3);
    p.hline(2, 6, 8 + oy, P.bone); p.px(2, 8 + oy, P.toxic);
  } else {
    p.line(2, 4 + oy, 3, 8 + oy, P.gray3);
    p.line(2, 13 + oy, 3, 8 + oy, P.gray3);
  }
  // drawing arm
  p.vline(7 + oy, 9 + oy, 11, boneD);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 5 });

// projectile: bone arrow used by g_bonearcher
defineSprite('g_bonearrow', 8, 8, (p) => {
  p.hline(0, 6, 4, P.bone);
  p.hline(0, 5, 3, darken(P.bone, 0.2));
  p.px(6, 4, P.gray3); p.px(7, 4, P.steelL); // tip
  p.px(0, 3, P.toxic); p.px(0, 5, P.toxic);  // fletch
}, { anchor: [4, 4] });

// ---------------------------------------------------------------------------
// g_ghoul — hunched rotting carrion-eater. Reuses drawHunter base in sickly
// flesh tones, then adds gore, claw fingers and a dripping maw.
// ---------------------------------------------------------------------------
defineAnim('g_ghoul', 16, 18, 4, (p, f) => {
  const flesh = mix(P.greenD, P.skinD, 0.45);
  const fleshD = darken(flesh, 0.3);
  const fleshL = lighten(flesh, 0.22);
  drawHunter(p, f, { cloak: flesh, cloakD: fleshD, cloakL: fleshL, trim: P.blood, eye: P.poison, skin: flesh });
  const oy = (f === 1 || f === 3) ? -1 : 0;
  // sunken cheeks / rotten patches over the face shadow
  p.px(6, 9 + oy, P.blood); p.px(9, 8 + oy, P.blood);
  p.px(10, 10 + oy, fleshD);
  // exposed claw fingers
  p.px(2, 14 + oy, P.bone); p.px(2, 15 + oy, P.bone);
  p.px(13, 14 + oy, P.bone); p.px(13, 15 + oy, P.bone);
  // dripping maw
  p.rect(6, 10 + oy, 4, 1, P.blood);
  p.px(7, 11 + oy, P.red);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 6 });

